// Create a canvas for the background animation
const canvas = document.createElement("canvas");
document.body.appendChild(canvas);
const ctx = canvas.getContext("2d");

// Set canvas to cover the whole screen
canvas.style.position = "fixed";
canvas.style.top = "0";
canvas.style.left = "0";
canvas.style.zIndex = "-1"; // Behind everything else
canvas.style.pointerEvents = "none";

// Resize the canvas to fit the screen
function resizeCanvas() {
  canvas.width = window.innerWidth;
  canvas.height = window.innerHeight;
}
resizeCanvas();
window.addEventListener("resize", resizeCanvas);

// Number of particles and their properties
const numParticles = 200;
const particles = [];

// Particle class with swirl motion
class Particle {
  constructor(x, y, size, angle, speed, radius) {
    this.x = x; // Initial x position
    this.y = y; // Initial y position
    this.size = size; // Size of the particle
    this.angle = angle; // Current angle of rotation
    this.speed = speed; // Speed of rotation
    this.radius = radius; // Radius of the swirl
  }

  update() {
    // Update the angle to create the swirling motion
    this.angle += this.speed;

    // Calculate the new x and y based on the angle
    this.x = canvas.width / 2 + this.radius * Math.cos(this.angle);
    this.y = canvas.height / 2 + this.radius * Math.sin(this.angle);

    // Gradually change the radius for dynamic effect
    this.radius += Math.sin(this.angle * 0.1) * 0.5;
  }

  draw() {
    // Draw the particle as a glowing circle
    ctx.beginPath();
    ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
    ctx.fillStyle = "rgba(255, 255, 255, 0.7)";
    ctx.shadowBlur = 10;
    ctx.shadowColor = "white";
    ctx.fill();
    ctx.closePath();
  }
}

// Initialize particles with random properties
for (let i = 0; i < numParticles; i++) {
  const angle = Math.random() * Math.PI * 2; // Random starting angle
  const radius = Math.random() * 300 + 50; // Random radius from the center
  const speed = (Math.random() - 0.5) * 0.02; // Random speed for variety
  const size = Math.random() * 3 + 1; // Random size
  particles.push(
    new Particle(
      canvas.width / 2,
      canvas.height / 2,
      size,
      angle,
      speed,
      radius
    )
  );
}

// Animation loop for swirling particles
function animateSwirl() {
  ctx.clearRect(0, 0, canvas.width, canvas.height);

  // Update and draw each particle
  particles.forEach((particle) => {
    particle.update();
    particle.draw();
  });

  requestAnimationFrame(animateSwirl);
}

animateSwirl();
